        scope = "global"
        if service_name_or_id:
            scope = f"service:{service_name_or_id}"
        elif route_name_or_id:
            scope = f"route:{route_name_or_id}"
        print(f"Adding plugin: {name} (scope: {scope})")

        payload = {
            "name": name,
            "enabled": enabled,
        }
        if config:
            payload["config"] = config
        if tags:
            payload["tags"] = tags

        if service_name_or_id:
            endpoint = f"/services/{service_name_or_id}/plugins"
        elif route_name_or_id:
            endpoint = f"/routes/{route_name_or_id}/plugins"
        elif consumer_name_or_id:
            endpoint = f"/consumers/{consumer_name_or_id}/plugins"
        else:
            endpoint = "/plugins"

        result = self._request("POST", endpoint, payload)
        print(f"  [OK] Plugin '{name}' added (id: {result.get('id', 'N/A')})")
