    def purge_configuration(self):
        """Remove all routes, services, upstreams, plugins, and consumers."""
        print("\n[WARN] Purging all Kong configuration...")

        for route in self.list_routes():
            self.delete_route(route["id"])

        for service in self.list_services():
            self.delete_service(service["id"])

        for upstream in self.list_upstreams():
            self.delete_upstream(upstream["id"])

        for plugin in self.list_plugins():
            self.delete_plugin(plugin["id"])

        print("[OK] Configuration purged.\n")


